async function waitForDeployment(client, appName, envName, branchName, timeoutSeconds, gitSha) {
    const startTime = DateTime.utc();
    const getElapsedSeconds = () => DateTime.utc().diff(startTime, 'seconds').seconds;
    while (getElapsedSeconds() < timeoutSeconds) {
        const { data, error } = await client.GET('/v1/deployments/getStackInfoByGitBranch', {
            params: {
                query: {
                    appName,
                    envName,
                    gitBranch: branchName,
                },
                header: { Authorization: '' }, // real token added by middleware
            },
        });
        if (error) {
            throw new Error(`failed to get stack status with git_branch=${branchName}: ${JSON.stringify(error)}`);
        }
        if (data.argo.revision === gitSha && data.argo.synced_and_healthy) {
            core.info(`Stack with git_branch=${branchName} is synced and healthy. Stack Info: ${JSON.stringify(data, null, 2)}`);
            return data;
        }
        const statusData = `Revision=${data.argo.revision}, Sync=${data.argo.sync.status}, Health=${data.argo.health.status}.`;
        core.info(`[${data.argo.checked_at}] Still waiting for stack to become synced and health. ${statusData}`);
        await snooze(5000);
    }
    throw new Error(`Stack with git_branch=${branchName} did not sync and become healthy within ${timeoutSeconds} seconds`);
}

